transform_js:
const categories = [];
// ウォーターフォールを描くには、「見えない土台（透明のバー）」と「増減分（実際の値を示すバー）」のStacked Barを活用します。
const baseData = []; // 透明な土台部分
const plusData = []; // プラスの要因
const minusData = []; // マイナスの要因

let currentTotal = 0;

rawData.rows.forEach((r, index) => {
  categories.push(r.step);

  if (index === 0 || index === rawData.rows.length - 1) {
    // 最初と最後は合計値の扱いとして、土台を0にして値をそのまま見せる
    baseData.push(0);
    // 今期利益があらかじめ与えられていても計算値と合わせる（デモ用）
    if (index === rawData.rows.length - 1) {
       plusData.push(currentTotal);
    } else {
       plusData.push(r.value);
       currentTotal = r.value;
    }
    minusData.push('-');
  } else {
    if (r.value > 0) {
       baseData.push(currentTotal);
       plusData.push(r.value);
       minusData.push('-');
       currentTotal += r.value;
    } else {
       currentTotal += r.value; // 値がマイナスなので減る
       baseData.push(currentTotal);
       minusData.push(-r.value); // 描画用に絶対値にする
       plusData.push('-');
    }
  }
});
transformedData = { categories, baseData, plusData, minusData };

echarts_js:
option = {
  title: {
    text: 'Profit Waterfall Chart',
    subtext: 'From Previous to Current',
    left: 'center'
  },
  tooltip: {
    trigger: 'axis',
    axisPointer: { type: 'shadow' },
    formatter: function (params) {
      let tar = params[1]; // Plus data
      if (tar.value === '-') {
         tar = params[2]; // Minus data if plus is empty
      }
      // 土台(params[0])は表示しない
      let valName = tar.seriesName;
      let val = tar.value;
      if (valName === 'Decrease') val = '-' + val;
      return tar.name + '<br/>' + tar.seriesName + ' : ' + val;
    }
  },
  legend: {
    data: ['Increase', 'Decrease'],
    bottom: '5%'
  },
  grid: {
    left: '3%',
    right: '4%',
    bottom: '15%',
    containLabel: true
  },
  xAxis: {
    type: 'category',
    splitLine: { show: false },
    data: transformedData.categories,
    axisLabel: { interval: 0, rotate: 30 }
  },
  yAxis: {
    type: 'value'
  },
  series: [
    {
      name: 'Base',
      type: 'bar',
      stack: 'Total',
      itemStyle: {
        borderColor: 'transparent',
        color: 'transparent'
      },
      emphasis: {
        itemStyle: {
          borderColor: 'transparent',
          color: 'transparent'
        }
      },
      data: transformedData.baseData
    },
    {
      name: 'Increase',
      type: 'bar',
      stack: 'Total',
      label: { show: true, position: 'top' },
      itemStyle: { color: '#91cc75' },
      data: transformedData.plusData
    },
    {
      name: 'Decrease',
      type: 'bar',
      stack: 'Total',
      label: { show: true, position: 'bottom' },
      itemStyle: { color: '#ee6666' },
      data: transformedData.minusData
    }
  ]
};
